%[text] # 例3.6（Prewittフィルタ）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example03_08"; % mfilename

imgname = "msipimg04";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');
%%
%[text] ## フィルタ処理前の画像表示
figure(1) %[output:64078bdf]
imshow(X)  %[output:64078bdf]
title('原画像')  %[output:64078bdf]

%%
%[text] ## 垂直方向差分
f = flipud(fspecial('prewitt'));
Xv = imfilter(X,f,'corr','same');
f = rot90(flipud(fspecial('prewitt')));
Xh = imfilter(X,f,'corr','same');

%%
%[text] ## フィルタ処理後の画像表示
Ymag = (Xv.^2+Xh.^2).^0.5;
Yang = atan2(Xv,Xh);
figure(2) %[output:9707bd9f]
H = mod(Yang,2*pi)/(2*pi);
S = Ymag/max(Ymag(:));
V = Ymag/max(Ymag(:));
Y = hsv2rgb(cat(3,H,S,V));
imshow(Y)  %[output:9707bd9f]

%%
%[text] ## フィルタ処理後の画像表示
figure(3) %[output:7d7cdcfe]
quiver(Xh,Xv,0,'k','LineWidth',0.1)  %[output:7d7cdcfe]
axis equal %[output:7d7cdcfe]
axis off %[output:7d7cdcfe]
axis ij %[output:7d7cdcfe]
ax = gca;

%%
%[text] ## 結果出力
imwrite(X,fullfile(resfolder,myfilename+"org.png"))
imwrite(Y,fullfile(resfolder,myfilename+"grd.png"))
exportgraphics(ax,fullfile(resfolder,"fig03-05c.png"),'Resolution',600) %[output:39e361f2]

